import React, { useState, useEffect } from 'react';
import { BrowserRouter as Router, Routes, Route, useNavigate, Link, useLocation } from 'react-router-dom';
import axios from 'axios';
import './App.css';

// --- THÀNH PHẦN DÙNG CHUNG: SIDEBAR ---
function Sidebar() {
    const location = useLocation();

    // Hàm kiểm tra xem link có đang được chọn không để đổi màu
    const activeClass = (path) => location.pathname === path ? "active-link" : "";

    return (
        <div className="sidebar">
            <div className="sidebar-header">MyAdmin</div>
            <ul className="sidebar-menu">
                <li className={activeClass('/dashboard')}><Link to="/dashboard">Dashboard</Link></li>
                <li className={activeClass('/employees')}><Link to="/employees">Hồ sơ nhân viên</Link></li>
                <li className={activeClass('/attendance')}><Link to="/attendance">Chấm công</Link></li>
                <li className={activeClass('/contracts')}><Link to="/contracts">Hợp đồng</Link></li>
                <li className={activeClass('/salary')}><Link to="/salary">Bảng lương</Link></li>
                <li className={activeClass('/accounts')}><Link to="/accounts">Tài khoản</Link></li>
            </ul>
        </div>
    );
}

// --- THÀNH PHẦN DÙNG CHUNG: TOPBAR ---
function TopBar() {
    return (
        <div className="top-bar">
            <span className="system-title">HỆ THỐNG QUẢN LÝ NHÂN SỰ</span>
            <div className="user-info">
                <span>Chào Admin | <Link to="/" style={{ color: '#fff', textDecoration: 'none' }}>Đăng xuất</Link></span>
            </div>
        </div>
    );
}

// --- TRANG ĐĂNG NHẬP ---
function LoginPage() {
    const navigate = useNavigate();
    const [user, setUser] = useState('');
    const [pass, setPass] = useState('');

    const handleLogin = (e) => {
        e.preventDefault();
        navigate('/dashboard'); // Cho phép vào thẳng dashboard
    };

    return (
        <div className="login-page">
            <div className="login-card">
                <h2>HỆ THỐNG NHÂN SỰ</h2>
                <form onSubmit={handleLogin}>
                    <div className="input-group">
                        <label>Username</label>
                        <input type="text" value={user} onChange={(e) => setUser(e.target.value)} required />
                    </div>
                    <div className="input-group">
                        <label>Password</label>
                        <input type="password" value={pass} onChange={(e) => setPass(e.target.value)} required />
                    </div>
                    <button type="submit" className="btn-login">ĐĂNG NHẬP</button>
                </form>
            </div>
        </div>
    );
}

// --- TRANG DASHBOARD (TỔNG QUAN) ---
function DashboardPage() {
    const [stats, setStats] = useState({ employees: 0, teachers: 12, budget: "150.000.000 đ" });

    useEffect(() => {
        axios.get("http://localhost:8080/api/employees")
            .then(res => setStats(prev => ({ ...prev, employees: res.data.length })))
            .catch(err => console.error("Lỗi kết nối Backend:", err));
    }, []);

    return (
        <div className="dashboard-layout">
            <Sidebar />
            <div className="main-content">
                <TopBar />
                <div className="content-body">
                    <div className="stats-grid">
                        <div className="stat-card border-blue">
                            <p>SỐ NHÂN VIÊN</p>
                            <h4>{stats.employees}</h4>
                        </div>
                        <div className="stat-card border-green">
                            <p>SỐ GIẢNG VIÊN</p>
                            <h4>{stats.teachers}</h4>
                        </div>
                        <div className="stat-card border-yellow">
                            <p>TỔNG LƯƠNG THÁNG</p>
                            <h4>{stats.budget}</h4>
                        </div>
                    </div>
                    <div className="welcome-section">
                        <h3>Dashboard Tổng Quan</h3>
                        <p>Chào mừng bạn quay trở lại hệ thống quản trị.</p>
                    </div>
                </div>
            </div>
        </div>
    );
}

// --- TRANG HỒ SƠ NHÂN VIÊN ---
function EmployeePage() {
    const [employees, setEmployees] = useState([]);
    const [showModal, setShowModal] = useState(false);
    const [newEmployee, setNewEmployee] = useState({ fullName: '', department: 'Nhân sự', position: 'Nhân viên' });

    useEffect(() => {
        axios.get("http://localhost:8080/api/employees")
            .then(res => setEmployees(res.data))
            .catch(err => console.error(err));
    }, []);

    const handleSaveEmployee = (e) => {
        e.preventDefault();
        // Giả lập lưu thành công (Nếu có API POST thì gọi axios.post ở đây)
        const newEmpWithId = { ...newEmployee, id: Date.now() };
        setEmployees([...employees, newEmpWithId]);
        setShowModal(false);
        setNewEmployee({ fullName: '', department: 'Nhân sự', position: 'Nhân viên' });
    };

    return (
        <div className="dashboard-layout">
            <Sidebar />
            <div className="main-content">
                <TopBar />
                <div className="content-body">
                    <div className="header-action">
                        <h3>Hồ sơ nhân viên / giảng viên</h3>
                        <button className="btn-primary" onClick={() => setShowModal(true)}>+ Thêm mới</button>
                    </div>
                    <table className="data-table">
                        <thead>
                            <tr>
                                <th>Họ Tên</th>
                                <th>Phòng ban</th>
                                <th>Chức vụ</th>
                                <th>Thao tác</th>
                            </tr>
                        </thead>
                        <tbody>
                            {employees.map(emp => (
                                <tr key={emp.id}>
                                    <td className="font-bold">{emp.fullName}</td>
                                    <td>{emp.department}</td>
                                    <td>{emp.position}</td>
                                    <td>
                                        <button className="btn-sm btn-edit">Sửa</button>
                                        <button className="btn-sm btn-delete">Xóa</button>
                                    </td>
                                </tr>
                            ))}
                        </tbody>
                    </table>
                </div>
            </div>

            {/* Modal Thêm Nhân Viên */}
            {showModal && (
                <div className="modal-overlay">
                    <div className="modal-content">
                        <h3>Thêm nhân viên mới</h3>
                        <form onSubmit={handleSaveEmployee}>
                            <div className="form-group">
                                <label>Họ và Tên</label>
                                <input type="text" value={newEmployee.fullName} onChange={e => setNewEmployee({ ...newEmployee, fullName: e.target.value })} required placeholder="Nhập họ và tên..." />
                            </div>
                            <div className="form-group">
                                <label>Phòng ban</label>
                                <select value={newEmployee.department} onChange={e => setNewEmployee({ ...newEmployee, department: e.target.value })}>
                                    <option value="Nhân sự">Nhân sự</option>
                                    <option value="Kế toán">Kế toán</option>
                                    <option value="Đào tạo">Đào tạo</option>
                                    <option value="Công nghệ thông tin">Công nghệ thông tin</option>
                                </select>
                            </div>
                            <div className="form-group">
                                <label>Chức vụ</label>
                                <select value={newEmployee.position} onChange={e => setNewEmployee({ ...newEmployee, position: e.target.value })}>
                                    <option value="Nhân viên">Nhân viên</option>
                                    <option value="Trưởng phòng">Trưởng phòng</option>
                                    <option value="Chuyên viên">Chuyên viên</option>
                                    <option value="Giảng viên">Giảng viên</option>
                                </select>
                            </div>
                            <div className="form-actions">
                                <button type="button" className="btn-secondary" onClick={() => setShowModal(false)}>Hủy</button>
                                <button type="submit" className="btn-primary">Lưu thông tin</button>
                            </div>
                        </form>
                    </div>
                </div>
            )}
        </div>
    );
}

// --- TRANG CHẤM CÔNG ---
function AttendancePage() {
    return (
        <div className="dashboard-layout">
            <Sidebar />
            <div className="main-content">
                <TopBar />
                <div className="content-body">
                    <h3>Chấm công theo ngày/giờ</h3>
                    <div className="card shadow-sm p-4">
                        <p>Lịch chấm công tháng {new Date().getMonth() + 1}</p>
                        <div className="alert-info">Chức năng này đang được kết nối với hệ thống máy chấm công vân tay...</div>
                    </div>
                </div>
            </div>
        </div>
    );
}


// --- 5. TRANG QUẢN LÝ HỢP ĐỒNG ---
function ContractPage() {
    const [contracts, setContracts] = useState([
        { id: 1, maHD: 'HD-001', nhanVien: 'Nguyễn Văn A', loaiHopDong: 'Vô thời hạn', ngayKy: '01/01/2024', trangThai: 'Đang hiệu lực' }
    ]);
    const [showModal, setShowModal] = useState(false);
    const [newContract, setNewContract] = useState({ maHD: '', nhanVien: '', loaiHopDong: '1 năm', ngayKy: '', trangThai: 'Đang hiệu lực' });

    const handleSaveContract = (e) => {
        e.preventDefault();
        const contractWithId = { ...newContract, id: Date.now() };
        setContracts([...contracts, contractWithId]);
        setShowModal(false);
        setNewContract({ maHD: '', nhanVien: '', loaiHopDong: '1 năm', ngayKy: '', trangThai: 'Đang hiệu lực' });
    };

    return (
        <div className="dashboard-layout">
            <Sidebar />
            <div className="main-content">
                <TopBar />
                <div className="content-body">
                    <div className="header-action">
                        <h3>Quản lý hợp đồng lao động</h3>
                        <button className="btn-primary" onClick={() => setShowModal(true)}>+ Tạo hợp đồng mới</button>
                    </div>
                    <div className="card-info shadow-sm">
                        <p>Danh sách hợp đồng sắp hết hạn: <strong>3 hợp đồng</strong></p>
                    </div>
                    <table className="data-table">
                        <thead>
                            <tr>
                                <th>Mã HĐ</th>
                                <th>Nhân viên</th>
                                <th>Loại hợp đồng</th>
                                <th>Ngày ký</th>
                                <th>Trạng thái</th>
                            </tr>
                        </thead>
                        <tbody>
                            {contracts.map(contract => (
                                <tr key={contract.id}>
                                    <td className="font-bold">{contract.maHD}</td>
                                    <td>{contract.nhanVien}</td>
                                    <td>{contract.loaiHopDong}</td>
                                    <td>{contract.ngayKy}</td>
                                    <td>
                                        <span className={contract.trangThai === "Đang hiệu lực" ? "status-active" : ""}>
                                            {contract.trangThai}
                                        </span>
                                    </td>
                                </tr>
                            ))}
                        </tbody>
                    </table>
                </div>
            </div>

            {/* Modal Thêm Hợp Đồng */}
            {showModal && (
                <div className="modal-overlay">
                    <div className="modal-content">
                        <h3>Tạo hợp đồng mới</h3>
                        <form onSubmit={handleSaveContract}>
                            <div className="form-group">
                                <label>Mã Hợp Đồng</label>
                                <input type="text" value={newContract.maHD} onChange={e => setNewContract({ ...newContract, maHD: e.target.value })} required placeholder="VD: HD-002" />
                            </div>
                            <div className="form-group">
                                <label>Tên Nhân Viên</label>
                                <input type="text" value={newContract.nhanVien} onChange={e => setNewContract({ ...newContract, nhanVien: e.target.value })} required placeholder="Nhập tên nhân viên..." />
                            </div>
                            <div className="form-group">
                                <label>Loại hợp đồng</label>
                                <select value={newContract.loaiHopDong} onChange={e => setNewContract({ ...newContract, loaiHopDong: e.target.value })}>
                                    <option value="1 năm">1 năm</option>
                                    <option value="3 năm">3 năm</option>
                                    <option value="Vô thời hạn">Vô thời hạn</option>
                                    <option value="Thử việc">Thử việc</option>
                                </select>
                            </div>
                            <div className="form-group">
                                <label>Ngày ký</label>
                                <input type="date" value={newContract.ngayKy} onChange={e => setNewContract({ ...newContract, ngayKy: e.target.value })} required />
                            </div>
                            <div className="form-actions">
                                <button type="button" className="btn-secondary" onClick={() => setShowModal(false)}>Hủy</button>
                                <button type="submit" className="btn-primary">Lưu hợp đồng</button>
                            </div>
                        </form>
                    </div>
                </div>
            )}
        </div>
    );
}

// --- 6. TRANG BẢNG LƯƠNG (Tính toán & Quản lý) ---
function SalaryPage() {
    // Tải dữ liệu từ localStorage, nếu không có lấy dữ liệu mẫu
    const initialData = JSON.parse(localStorage.getItem('salaryData')) || [
        { id: 1, name: 'Trần Thị B', base: 15000000, allowance: 2000000, deduction: 500000, net: 16500000 }
    ];

    const [salaries, setSalaries] = useState(initialData);

    // Lưu lại tiến trình mỗi khi mảng salaries thay đổi
    useEffect(() => {
        localStorage.setItem('salaryData', JSON.stringify(salaries));
    }, [salaries]);

    const handleCalculate = () => {
        // Giả lập tính lương bằng cách thêm 1 nhân viên mới vào danh sách
        const newSalary = {
            id: Date.now(),
            name: 'Nhân viên Mới ' + Math.floor(Math.random() * 100),
            base: 10000000,
            allowance: 1000000,
            deduction: 200000,
            net: 10800000
        };
        setSalaries([...salaries, newSalary]);
    };

    const handleExportCSV = () => {
        // Xuất dữ liệu sang file CSV
        const headers = ["Nhân viên", "Lương cơ bản", "Phụ cấp", "Khấu trừ", "Thực nhận"];
        const csvContent = [
            headers.join(","),
            ...salaries.map(s => `"${s.name}",${s.base},${s.allowance},${s.deduction},${s.net}`)
        ].join("\n");

        const blob = new Blob(["\uFEFF" + csvContent], { type: 'text/csv;charset=utf-8;' }); // \uFEFF hỗ trợ font Tiếng Việt
        const link = document.createElement("a");
        const url = URL.createObjectURL(blob);
        link.setAttribute("href", url);
        link.setAttribute("download", `bang_luong_thang_${new Date().getMonth() + 1}.csv`);
        link.style.visibility = 'hidden';
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
    };

    const formatCurrency = (amount) => {
        return new Intl.NumberFormat('vi-VN', { style: 'currency', currency: 'VND' }).format(amount);
    };

    return (
        <div className="dashboard-layout">
            <Sidebar />
            <div className="main-content">
                <TopBar />
                <div className="content-body">
                    <div className="header-action">
                        <h3>Bảng lương tháng {new Date().getMonth() + 1}</h3>
                        <div>
                            <button className="btn-secondary" style={{ marginRight: '10px' }} onClick={handleExportCSV}>Xuất báo cáo (CSV)</button>
                            <button className="btn-primary" onClick={handleCalculate}>Tính lương</button>
                        </div>
                    </div>
                    <table className="data-table">
                        <thead>
                            <tr>
                                <th>Nhân viên</th>
                                <th>Lương cơ bản</th>
                                <th>Phụ cấp</th>
                                <th>Khấu trừ</th>
                                <th>Thực nhận</th>
                            </tr>
                        </thead>
                        <tbody>
                            {salaries.map(s => (
                                <tr key={s.id}>
                                    <td className="font-bold">{s.name}</td>
                                    <td>{formatCurrency(s.base)}</td>
                                    <td>{formatCurrency(s.allowance)}</td>
                                    <td>{formatCurrency(s.deduction)}</td>
                                    <td style={{ color: '#1cc88a', fontWeight: 'bold' }}>{formatCurrency(s.net)}</td>
                                </tr>
                            ))}
                        </tbody>
                    </table>
                </div>
            </div>
        </div>
    );
}

